INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'deuda_patrimonio_1Q', 2023, 2023, '1Q', 'success', 'Tu relaciÃ³n deuda a patrimonio de 0.50x en este primer trimestre es el reflejo de un balance sumamente saneado. Tienes dos veces mÃ¡s capital propio que deuda total, lo que te garantiza una capacidad de respuesta inmediata ante cualquier imprevisto financiero sin poner en riesgo la viabilidad del negocio.', 'No obstante, este ratio tan bajo puede ser interpretado como falta de confianza en los proyectos futuros. Pareciera que prefieres guardar el dinero bajo el colchÃ³n patrimonial en lugar de ponerlo a trabajar mediante un apalancamiento productivo que maximice el valor de la compaÃ±Ã­a en este inicio de aÃ±o tan prometedor.', 'Te sugiero que definas un corredor de apalancamiento ideal entre 0.8x y 1.2x. Estar en este rango te permitirÃ­a ser mucho mÃ¡s agresivo comercialmente sin abandonar nunca los niveles de solvencia que hoy protegen tu tranquilidad personal y la de tus socios estratÃ©gicos en este periodo.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_2Q', 2023, 2023, '2Q', 'success', 'Llegamos a mitad de aÃ±o con una relaciÃ³n deuda-patrimonio inalterable. Has logrado que el crecimiento del pasivo operativo sea compensado perfectamente por la retenciÃ³n de utilidades, manteniendo una equilibrio estructural que es garantÃ­a de estabilidad para todos tus colaboradores y proveedores de confianza.', 'Sin embargo, notamos que tu patrimonio estÃ¡ "financiando" a tus clientes de manera gratuita. Tu solidez patrimonial estÃ¡ permitiendo que otros se demoren en pagarte, consumiendo tu riqueza neta sin generar un retorno financiero por esa mora administrativa. EstÃ¡s siendo el banco gratuito de tus clientes corporativos.', 'Ajusta tus polÃ­ticas de cobro de inmediato. No permitas que tu bajÃ­sima relaciÃ³n deuda-patrimonio sea la excusa para que tus clientes no te paguen a tiempo. Tu patrimonio es para tu crecimiento, no para subsidiar la operaciÃ³n de terceros que no te retribuyen esa solvencia con puntualidad de pago.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_3Q', 2023, 2023, '3Q', 'success', 'En este tercer periodo, la relaciÃ³n deuda-patrimonio de 0.50x sigue siendo tu mejor escudo. Es una cifra que comunica confianza absoluta al mercado, permitiÃ©ndote negociar crÃ©ditos de gran escala si decidieras comprarlos con el fin de diversificar tus servicios o expandirte a nuevas geografÃ­as de forma inmediata.', 'El punto de atenciÃ³n es que la inercia de este nÃºmero tan bajo puede estancarte creativamente. Al no tener la presiÃ³n de las deudas, podrÃ­as estar perdiendo el sentido de urgencia por innovar y optimizar costos. La "paz patrimonial" excesiva a veces adormece el instinto de competencia empresarial mÃ¡s agresivo.', 'EvalÃºa la toma de un crÃ©dito de inversiÃ³n estructurado para este cierre de aÃ±o. Tienes la espalda patrimonial suficiente para absorberlo y usarlo como combustible para un 2024 de crecimiento explosivo. No dejes que el Ã©xito de tu solvencia se convierta en el techo de tu expansiÃ³n comercial futura.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_4Q', 2023, 2023, '4Q', 'success', 'Cerras el trienio de 2023 con una relaciÃ³n deuda-patrimonio de 0.50x, reafirmando tu compromiso con la solidez estructural. Es un balance de "oro" que te deja en una posiciÃ³n inigualable para negociar cualquier alianza estratÃ©gica en el 2024, con un respaldo patrimonial que garantiza tu libertad total como socio.', 'A pesar del Ã©xito, vemos que no has aprovechado el apalancamiento para mejorar tu ROE (Retorno sobre Patrimonio). Tu rentabilidad final depende exclusivamente de tus mÃ¡rgenes operativos y no de tu eficiencia financiera. EstÃ¡s operando con un solo motor cuando podrÃ­as tener dos trabajando a mÃ¡xima potencia.', 'Para el 2024, tu reto es subir este indicador a un nivel de 0.9x mediante deuda productiva de largo plazo. Debes aprender a multiplicar el valor de tu capital propio usando recursos de terceros que tengan un costo inferior a tu tasa de retorno esperada. Es el paso necesario para pasar de ser solvente a ser un titÃ¡n del sector.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
