INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologÃ­a, generado_por, created_at)
VALUES 
(3099, 'deuda_tangibles_1Q', 2025, 2025, '1Q', 'success', 'Al iniciar el 2025, tu relaciÃ³n de deuda sobre activos tangibles es prÃ¡cticamente inexistente, lo que te otorga una solvencia fÃ­sica absoluta. Has logrado que cada equipo y herramienta de MAS CONSULTA sea propiedad neta de los socios, eliminando cualquier sombra de embargo o restricciÃ³n operativa por parte de acreedores externos hoy.', 'El riesgo paradÃ³jico es que tus activos tangibles se estÃ¡n volviendo "viejos" en tÃ©rminos contables y tecnolÃ³gicos. Al no usar deuda para renovarlos, estÃ¡s permitiendo que tu infraestructura pierda valor de mercado por obsolescencia, lo que podrÃ­a restarte competitividad ante nuevas licitaciones que exijan tecnologÃ­a de punta neta.', 'Inicia un plan de renovaciÃ³n de infraestructura tÃ©cnica usando el 10% de tu excedente de capitalizaciÃ³n de este trimestre. No necesitas endeudarte; tienes la fuerza para comprar lo mejor del mercado al contado, asegurando que tu respaldo tangible sea moderno, eficiente y altamente productivo de inmediato hoy dÃ­a.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'deuda_tangibles_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de aÃ±o con activos fÃ­sicos que son el pilar de una solvencia indestructible. Has demostrado que es posible escalar una firma de consultorÃ­a manteniendo la propiedad total de sus herramientas de producciÃ³n, lo que te brinda una credibilidad excepcional ante cualquier socio estratÃ©gico o inversionista global neta.', 'La nota de cautela es la baja rotaciÃ³n de tus activos tangibles. Tienes equipos que ya cumplieron su ciclo de vida productivo pero que siguen en el balance por "limpieza" financiera. Mantener activos obsoletos es una forma de ineficiencia que castiga tus mÃ¡rgenes brutos debido a mayores costos de mantenimiento y menor velocidad neta.', 'Ejecuta un plan de chatarrizaciÃ³n o venta de activos antiguos de forma inmediata. Debes limpiar tu balance de todo lo que no sume valor operativo real; quÃ©date solo con lo que te haga mÃ¡s rÃ¡pido y eficiente. Tu meta es tener una base tangible liviana pero sumamente potente para el cierre de semestre hoy mismo.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'deuda_tangibles_3Q', 2025, 2025, '3Q', 'success', 'En el tercer periodo, tu respaldo fÃ­sico patrimonial sigue siendo un escudo de protecciÃ³n inexpugnable. Has logrado que MAS CONSULTA sea una empresa con "raÃ­ces de acero", donde el patrimonio neto cubre con creces cualquier fluctuaciÃ³n en la valoraciÃ³n de mercado de tus activos operativos pesados y tecnolÃ³gicos hoy.', 'El riesgo es que no estÃ¡s aprovechando este colosal respaldo fÃ­sico para apalancarte en proyectos de infraestructura masiva. EstÃ¡s operando con el freno de mano puesto en cuanto a inversiÃ³n fÃ­sica se refiere, lo que podrÃ­a limitar tu capacidad de atender a grandes multinacionales que exigen sedes y tecnologÃ­a de escala continental.', 'EvalÃºa el leasing de una nueva sede corporativa inteligente o un centro de datos propio este mes. Tienes el respaldo tangible para obtener las mejores tasas del mercado; usa tu propiedad actual como garantÃ­a para dar el salto hacia una infraestructura de clase mundial que te posicione como el lÃ­der absoluto neta.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'deuda_tangibles_4Q', 2025, 2025, '4Q', 'success', 'Cierras el trienio 2023-2025 con una relaciÃ³n deuda-tangibles ejemplar, consolidando un balance que es el reflejo de una gestiÃ³n de activos magistral. Has terminado el aÃ±o con una infraestructura operativa 100% propia y saneada, garantizando una libertad de acciÃ³n total para los ambiciosos retos de expansiÃ³n del prÃ³ximo ciclo.', 'Para el 2026, el reto es mantener la agilidad fÃ­sica. El mundo de la consultorÃ­a se mueve hacia activos intangibles y modelos "asset-light". No te enamores de tus activos fijos; asegÃºrate de que tu patrimonio los cubra pero que no te aten a modelos de negocio estÃ¡ticos que te quiten velocidad de respuesta hoy.', 'DiseÃ±a una estructura de activos para el prÃ³ximo trienio que priorice la flexibilidad y la movilidad tecnolÃ³gica. Tu base tangible debe ser el soporte de tu conocimiento, no una carga que te impida pivotar hacia nuevas oportunidades digitales globales. MantÃ©n la solvencia pero aumenta la agilidad fÃ­sica de inmediato neta.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
