INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologÃ­a, generado_por, created_at)
VALUES 
(3099, 'deuda_patrimonio_1Q', 2025, 2025, '1Q', 'success', 'Inicias el 2025 con una relaciÃ³n deuda-patrimonio de 0.10x, lo que representa un estado de "deuda cero" operativa virtual. Tu patrimonio es diez veces superior a tus compromisos totales, lo que te otorga un perfil de riesgo prÃ¡cticamente nulo y una capacidad de negociaciÃ³n ante proveedores y bancos que es invencible hoy.', 'El riesgo latente es la ineficiencia econÃ³mica de no usar apalancamiento productivo. Al operar solo con dinero propio, estÃ¡s pagando un "costo de oportunidad" muy alto, ya que podrÃ­as estar rindiendo mucho mÃ¡s si usaras capital de terceros para financiar tu expansiÃ³n mientras mantienes tu riqueza invertida en activos neta.', 'AtrÃ©vete a tomar una deuda estratÃ©gica de bajo costo para financiar tu nueva unidad de negocios digital este semestre. Tienes la espalda patrimonial para hacerlo sin riesgo alguno; usa la deuda como un atajo para el crecimiento y no como un salvavidas de emergencia, que es como la usabas en Ã©pocas pasadas hoy.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de aÃ±o con una relaciÃ³n deuda-patrimonio que es el estÃ¡ndar de oro de la industria consultora. Has logrado que tu riqueza neta crezca exponencialmente gracias a utilidades rÃ©cord, mientras tus deudas se mantienen en niveles marginales, dÃ¡ndote una solidez institucional que proyecta confianza total hoy.', 'La alerta aquÃ­ es el potencial descuido de la gestiÃ³n de tesorerÃ­a operativa. Al tener tanto patrimonio, podrÃ­as estar permitiendo que tus cuentas por cobrar se dilaten, confiando en que tu "propio banco" patrimonial cubrirÃ¡ los baches. No permitas que la solvencia te vuelva perezoso en el recaudo comercial de MAS CONSULTA.', 'Implementa un sistema de recaudo agresivo con incentivos por pronto pago de inmediato. Tu patrimonio debe ser para invertir y crecer, no para financiar gratis la operaciÃ³n de tus clientes. Asegura que cada peso que debas tenga un respaldo de caja inmediata y que tus deudas sigan siendo insignificantes hoy.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_3Q', 2025, 2025, '3Q', 'success', 'En el tercer trimestre, tu relaciÃ³n de deuda sobre patrimonio sigue siendo magistralmente baja (0.12x). Has construido una estructura de fondeo donde los dueÃ±os son los Ãºnicos proveedores reales de capital estratÃ©gico, eliminando cualquier vulnerabilidad ante cambios en las tasas de interÃ©s o crisis de crÃ©dito nacional.', 'No obstante, vigila que esta baja deuda no sea sÃ­ntoma de una falta de ambiciÃ³n corporativa. El mercado de hoy exige movimientos rÃ¡pidos que a veces requieren deudas puentes masivas para capturar licitaciones de gran volumen. Si eres demasiado cauteloso con la deuda, podrÃ­as estarle regalando el mercado a novatos mÃ¡s audaces hoy.', 'Crea un cupo de deuda pre-aprobado para adquisiciones estratÃ©gicas este mes. Debes tener el gatillo listo para disparar ante una oportunidad de compra de infraestructura o talento; usa tu ratio de 0.12x como la mejor carta de presentaciÃ³n para que los bancos te ofrezcan cheques en blanco para tu crecimiento corporativo neta.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_4Q', 2025, 2025, '4Q', 'success', 'Cierras el trienio 2023-2025 con una relaciÃ³n deuda-patrimonio de 0.10x, coronando una gestiÃ³n de solvencia histÃ³rica y vencedora. Has transformado a MAS CONSULTA en una fortaleza financiera inexpugnable, donde hoy por cada peso que debes, tienes diez pesos de patrimonio neto propio respaldando la operaciÃ³n consolidada.', 'Para el 2026, el desafÃ­o es pasar de la "solvencia defensiva" a la "solvencia expansiva". Ya demostraste que puedes vivir sin deuda; ahora debes demostrar que puedes usarla para dominar el continente sin perder tu esencia de control patrimonial. No permitas que el miedo a deber te impida ser el mÃ¡s grande de la regiÃ³n hoy.', 'DiseÃ±a la estructura de capital para el 2026 con un objetivo de apalancamiento del 0.4x destinado exclusivamente a la internacionalizaciÃ³n. Tienes la base patrimonial mÃ¡s sÃ³lida de tu historia; Ãºsala ahora como el motor de una expansiÃ³n que no conozca fronteras, manteniendo siempre tu libertad de dueÃ±o soberana neta.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
